    /**
     * Typed configuration for a Databricks batch-export destination.
     *
     * Credentials live in the linked Integration, not in this config. Mirrors
     * `DatabricksBatchExportInputs` in `products/batch_exports/backend/service.py`.
     */
    export interface DatabricksDestinationConfig {
      /** Databricks SQL warehouse HTTP path. */
      http_path: string;
      /** Unity Catalog name. */
      catalog: string;
      /** Schema (database) name inside the catalog. */
      schema: string;
      /** Destination table name. */
      table_name: string;
      /** Whether to use the Databricks VARIANT type for JSON-like columns. */
      use_variant_type?: boolean;
      /** Whether to let Databricks evolve the destination table schema automatically. */
      use_automatic_schema_evolution?: boolean;
      type: DatabricksDestinationConfigType;
    }

    export type BigQueryDestinationConfigType = typeof BigQueryDestinationConfigType[keyof typeof BigQueryDestinationConfigType];


    export const BigQueryDestinationConfigType = {
      BigQuery: 'BigQuery',
    } as const;

    /**
     * Typed configuration for a BigQuery batch-export destination.
     *
     * Credentials live in the linked Integration, not in this config. Mirrors the
     * non-credential fields of `BigQueryBatchExportInputs` in
     * `products/batch_exports/backend/service.py`.
     */
    export interface BigQueryDestinationConfig {
      /** BigQuery dataset ID to write to. */
      dataset_id: string;
      /** BigQuery table ID inside the dataset. */
      table_id?: string;
      /** Whether to export 'properties', 'set', and 'set_once' fields as the BigQuery JSON type rather than STRING. Cannot be changed after the export is created. */
      use_json_type?: boolean;
      type: BigQueryDestinationConfigType;
    }

    export type PostgresDestinationConfigType = typeof PostgresDestinationConfigType[keyof typeof PostgresDestinationConfigType];


    export const PostgresDestinationConfigType = {
      Postgres: 'Postgres',
    } as const;

    /**
     * Typed configuration for a PostgreSQL batch-export destination.
     *
     * Connection credentials may live in a linked Integration (when one is provided) or
     * inline in this config (legacy). Mirrors the non-credential fields of
     * `PostgresBatchExportInputs` in `products/batch_exports/backend/service.py`.
     */
    export interface PostgresDestinationConfig {
      /** PostgreSQL database name to connect to. */
      database: string;
      /** PostgreSQL schema name containing the destination table. */
      schema?: string;
      /** PostgreSQL table name to write exported rows into. */
      table_name?: string;
      /** Legacy SSL option for direct credential configuration. Ignored when using a PostgreSQL integration. */
      has_self_signed_cert?: boolean;
      type: PostgresDestinationConfigType;
    }

    export type S3CompatibleDestinationConfigType = typeof S3CompatibleDestinationConfigType[keyof typeof S3CompatibleDestinationConfigType];


    export const S3CompatibleDestinationConfigType = {
      S3Compatible: 'S3Compatible',
    } as const;

    /**
     * Typed configuration for an S3-compatible batch-export destination (Cloudflare R2,
     * DigitalOcean Spaces, etc.).
     *
     * Credentials and the provider `endpoint_url` live in the linked s3-compatible Integration.
     * Mirrors the non-credential fields of `S3CompatibleBatchExportInputs` in
     * `products/batch_exports/backend/service.py`.
     */
    export interface S3CompatibleDestinationConfig {
      /** Name of the destination bucket. */
      bucket_name: string;
      /** Region the bucket is in (e.g. 'us-east-1'). */
      region: string;
      /** Object key prefix applied to every exported file. */
      prefix: string;
      /** Optional compression codec applied to exported files. Valid codecs depend on file_format.
       *
       * * `brotli` - brotli
       * * `gzip` - gzip
       * * `lz4` - lz4
       * * `snappy` - snappy
       * * `zstd` - zstd */
      compression?: CompressionEnum | null;
      /** File format used for exported objects.
       *
       * * `Parquet` - Parquet
       * * `JSONLines` - JSONLines */
      file_format?: FileFormatEnum;
      /**
         * If set, rolls to a new file once the current file exceeds this size in MB.
         * @nullable
         */
      max_file_size_mb?: number | null;
      /** Use virtual-hosted-style addressing rather than path-style. */
      use_virtual_style_addressing?: boolean;
      type: S3CompatibleDestinationConfigType;
    }

    export type BatchExportDestinationConfig = DatabricksDestinationConfig | AzureBlobDestinationConfig | BigQueryDestinationConfig | PostgresDestinationConfig | AwsS3DestinationConfig | S3CompatibleDestinationConfig;

    /**
     * Serializer for an BatchExportDestination model.
     *
     * The `config` field is polymorphic and typed only for destinations that keep
     * credentials in the linked Integration (currently Databricks, AzureBlob, BigQuery, Postgres,
     * AwsS3, S3Compatible). Other destination types accept the same JSON shape but without a typed
     * OpenAPI schema. Secret fields are stripped from `config` on read.
     */
    export interface BatchExportDestination {
      /** A choice of supported BatchExportDestination types.
       *
       * * `S3` - S3
       * * `AwsS3` - Aws S3
       * * `S3Compatible` - S3 Compatible
       * * `Snowflake` - Snowflake
       * * `Postgres` - Postgres
       * * `Redshift` - Redshift
       * * `BigQuery` - Bigquery
       * * `Databricks` - Databricks
       * * `AzureBlob` - Azure Blob
       * * `Workflows` - Workflows
       * * `HTTP` - Http
       * * `NoOp` - Noop
       * * `FileDownload` - File Download */
      type: BatchExportDestinationTypeEnum;
      /** Destination-specific configuration. Fields depend on `type`. Credentials for integration-backed destinations (Databricks, AzureBlob, BigQuery, Postgres, AwsS3, S3Compatible) are NOT stored here — they live in the linked Integration. Secret fields are stripped from responses. */
      config: BatchExportDestinationConfig;
      /**
         * The integration for this destination.
         * @nullable
         */
      integration?: number | null;
      /**
         * ID of a team-scoped Integration providing credentials. Required when creating Databricks, AzureBlob, and BigQuery destinations; optional for AwsS3 and S3Compatible (inline credentials remain supported); unused for other types.
         * @nullable
         */
      integration_id?: number | null;
    }

