    export interface PatchedProjectSecretAPIKey {
      readonly id?: string;
      /** @maxLength 40 */
      label?: string;
      readonly value?: string;
      /** @nullable */
      readonly mask_value?: string | null;
      readonly created_at?: string;
      readonly created_by?: UserBasic;
      /** @nullable */
      readonly last_used_at?: string | null;
      /** @nullable */
      readonly last_rolled_at?: string | null;
      /** Project-wide API scopes granted to this key. Project secret API keys do not honor object-level access controls, so a scope can access resources of that type even when per-resource RBAC would hide them from an individual user. */
      scopes?: string[];
    }

    export interface PatchedQueryTabState {
      readonly id?: string;
      /**
       *             Dict of query tab state for a user. Keys are editorModelsStateKey, activeModelStateKey, activeModelVariablesStateKey
       *             and values are the state for that key. EditorModelsStateKey is a list of all the editor models for a user.
       *             ActiveModelStateKey is the active model for a user. ActiveModelVariablesStateKey is the active model variables
       *             for a user.
       *              */
      state?: unknown;
    }

    export interface PatchedQuickFilter {
      readonly id?: string;
      /** @maxLength 200 */
      name?: string;
      /** @maxLength 500 */
      property_name?: string;
      type?: QuickFilterTypeEnum;
      options?: unknown;
      readonly contexts?: readonly string[];
      readonly created_at?: string;
      readonly updated_at?: string;
    }

    export interface PatchedReminder {
      readonly id?: string;
      /** ID of the organization this reminder belongs to. You must be a member of it. */
      organization?: string;
      /**
         * Optional ID of the project this reminder is scoped to. Required when targeting a specific resource. Must belong to the chosen organization.
         * @nullable
         */
      team?: number | null;
      /**
         * Short text shown as the notification title when the reminder fires.
         * @maxLength 255
         */
      title?: string;
      /** Optional longer body for the notification. */
      message?: string;
      /**
         * Optional PostHog resource this reminder is about. One of: dashboard, insight, experiment, feature_flag, survey, notebook, replay, error_tracking. Resources are project-scoped, so a team must be set when this is provided.
         * @maxLength 50
         * @nullable
         */
      resource_type?: string | null;
      /**
         * ID of the referenced resource; must exist in the chosen project.
         * @maxLength 200
         * @nullable
         */
      resource_id?: string | null;
      /**
         * For a one-off reminder: when it should fire (ISO 8601, future).
         * @nullable
         */
      scheduled_at?: string | null;
      /** For a recurring reminder: daily, weekly, monthly, or yearly.
       *
       * * `daily` - Daily
       * * `weekly` - Weekly
       * * `monthly` - Monthly
       * * `yearly` - Yearly */
      recurrence_interval?: RecurrenceIntervalEnum | BlankEnum | null;
      /**
         * For a recurring reminder: a 5-field cron expression (e.g. '0 9 * * 1' = Mondays 9am). May fire at most 4 times per day. Mutually exclusive with recurrence_interval.
         * @maxLength 100
         * @nullable
         */
      cron_expression?: string | null;
      /**
         * IANA timezone the schedule resolves in (e.g. 'America/New_York'). Defaults to the project timezone when a team is set, otherwise UTC.
         * @maxLength 64
         */
      timezone?: string;
      /**
         * Optional: recurring reminders stop (status=completed) after this time.
         * @nullable
         */
      end_date?: string | null;
      /** @nullable */
      readonly next_fire_at?: string | null;
      /** @nullable */
      readonly last_fired_at?: string | null;
      readonly status?: ReminderStatusEnum;
      readonly created_by?: UserBasic;
      readonly created_at?: string;
      /** @nullable */
      readonly updated_at?: string | null;
    }

    export interface PatchedRemovePersonRequest {
      /** Person UUID to remove from the cohort */
      person_id?: string;
    }

    export interface PatchedReplayScanner {
      readonly id?: string;
      /**
         * Human-readable scanner name. Unique within the team.
         * @maxLength 255
         */
      name?: string;
      /** Free-form description shown in the scanner management UI. */
      description?: string;
      /** What the scanner does: monitor, classifier, scorer, or summarizer.
       *
       * * `monitor` - Monitor
       * * `classifier` - Classifier
       * * `scorer` - Scorer
       * * `summarizer` - Summarizer */
      scanner_type?: ScannerTypeEnum;
      /** Type-specific configuration. All scanner types require `prompt`; monitors add optional `allow_inconclusive`, classifiers add `tags`, scorers add `scale`, summarizers add optional `length`. */
      scanner_config?: unknown;
      /** Persisted `RecordingsQuery` shape used to pick candidate sessions. `date_from`/`date_to` are stripped on save — the schedule controls time, not the user. */
      query?: unknown;
      /**
         * 0..1 random downsample applied after the query matches. Defaults to 1.0 (no downsampling).
         * @minimum 0
         * @maximum 1
         */
      sampling_rate?: number;
      /** LLM provider. v1 is Google-only.
       *
       * * `google` - Google */
      provider?: ScannerProviderEnum;
      /** Concrete model to use for this scanner.
       *
       * * `gemini-3-flash-preview` - Gemini 3 Flash
       * * `gemini-3.1-flash-lite-preview` - Gemini 3 Flash Lite */
      model?: ScannerModelEnum;
      /** When false, the reconciler removes the scanner's Temporal schedule. On-demand triggers still work. */
      enabled?: boolean;
      /** When true, the prompt is augmented with the Signal side mission and the scanner emits PostHog Signals. */
      emits_signals?: boolean;
      /** Increments on every config-changing save. Observations snapshot this value. */
      readonly scanner_version?: number;
      /**
         * Latest projected observations/month for this scanner. Null until first computed.
         * @nullable
         */
      readonly estimated_monthly_observations?: number | null;
      /** Watermark for the scanner's last scheduled fire. Mirrors Temporal schedule state for recovery. */
      readonly last_swept_at?: string;
      readonly created_at?: string;
      /** User who created the scanner. */
      readonly created_by?: UserBasic | null;
      readonly updated_at?: string;
    }

