    export interface SignalReportBulkStateRequest {
      /** Target state for the report. Use 'suppressed' to dismiss the report from the inbox, or 'potential' to snooze/reopen it for later review.
       *
       * * `suppressed` - suppressed
       * * `potential` - potential */
      state: SignalReportStateEnum;
      /** Optional canonical reason code for the dismissal. Must be one of: already_fixed, report_unclear, analysis_wrong, wontfix_intentional, wontfix_irrelevant, other — these match the inbox UI so the rationale renders as a labelled chip rather than a raw code. 'already_fixed' is a snooze, not a dismissal: pair it with state='potential' (restore) so the report reappears if the issue recurs. Use 'other' together with a dismissal_note for anything that doesn't fit a code.
       *
       * * `already_fixed` - Already fixed
       * * `report_unclear` - Report is unclear to me
       * * `analysis_wrong` - Agent's analysis is wrong
       * * `wontfix_intentional` - Won't fix - intentional behavior
       * * `wontfix_irrelevant` - Won't fix - issue is real but insignificant
       * * `other` - Something else… */
      dismissal_reason?: DismissalReasonEnum;
      /**
         * Optional free-form note explaining the dismissal. Capped at 4000 characters.
         * @maxLength 4000
         */
      dismissal_note?: string;
      /**
         * Optional, only honored when state is 'potential'. Number of additional signals the report must accumulate before it is re-promoted into the pipeline — effectively snoozing it until then. Omit to let the report re-enter the pipeline on the next matching signal.
         * @minimum 1
         * @maximum 100000
         */
      snooze_for?: number;
      /**
         * Report ids to transition to `state` in one call (1–100). Duplicates are de-duplicated; each id is processed independently so one disallowed transition does not block the rest. `dismissal_reason`, `dismissal_note` and `snooze_for` apply to every id.
         * @maxItems 100
         */
      ids: string[];
    }

    export interface SignalReportBulkStateResult {
      /** The report id this result refers to. */
      id: string;
      /** One of: transitioned, skipped, failed, not_found. transitioned: the state change was applied. skipped: the transition was not allowed from the report's current status (a 409 on the single-report endpoint). failed: the request data was invalid for this report. not_found: no report with this id is visible to you. */
      outcome: string;
      /**
         * The report's status after the transition. Present only when outcome is 'transitioned'.
         * @nullable
         */
      status?: string | null;
      /**
         * Human-readable explanation for non-transitioned outcomes (skipped / failed / not_found).
         * @nullable
         */
      detail?: string | null;
    }

    export interface SignalReportBulkStateResponse {
      /** One result per requested id, in request order (after de-duplication). */
      results: SignalReportBulkStateResult[];
      /** Number of reports whose state was changed. */
      transitioned_count: number;
      /** Number of reports whose transition was not allowed. */
      skipped_count: number;
      /** Number of reports that failed on invalid request data. */
      failed_count: number;
      /** Number of requested ids not visible to the caller. */
      not_found_count: number;
    }

    export interface SignalReportStateRequest {
      /** Target state for the report. Use 'suppressed' to dismiss the report from the inbox, or 'potential' to snooze/reopen it for later review.
       *
       * * `suppressed` - suppressed
       * * `potential` - potential */
      state: SignalReportStateEnum;
      /** Optional canonical reason code for the dismissal. Must be one of: already_fixed, report_unclear, analysis_wrong, wontfix_intentional, wontfix_irrelevant, other — these match the inbox UI so the rationale renders as a labelled chip rather than a raw code. 'already_fixed' is a snooze, not a dismissal: pair it with state='potential' (restore) so the report reappears if the issue recurs. Use 'other' together with a dismissal_note for anything that doesn't fit a code.
       *
       * * `already_fixed` - Already fixed
       * * `report_unclear` - Report is unclear to me
       * * `analysis_wrong` - Agent's analysis is wrong
       * * `wontfix_intentional` - Won't fix - intentional behavior
       * * `wontfix_irrelevant` - Won't fix - issue is real but insignificant
       * * `other` - Something else… */
      dismissal_reason?: DismissalReasonEnum;
      /**
         * Optional free-form note explaining the dismissal. Capped at 4000 characters.
         * @maxLength 4000
         */
      dismissal_note?: string;
      /**
         * Optional, only honored when state is 'potential'. Number of additional signals the report must accumulate before it is re-promoted into the pipeline — effectively snoozing it until then. Omit to let the report re-enter the pipeline on the next matching signal.
         * @minimum 1
         * @maximum 100000
         */
      snooze_for?: number;
    }

    /**
     * Per-(team, skill) scout config: schedule, enablement, and emit posture.
     *
     * One row per `signals-scout-*` skill on the team. The coordinator auto-creates a row
     * when it discovers a scout skill; this serializer lets agents tune the row.
     */
    export interface SignalScoutConfig {
      readonly id: string;
      /** The `signals-scout-*` skill this config controls. Set at creation, not editable. */
      readonly skill_name: string;
      /** Human-readable summary of what this scout investigates, sourced from the scout skill's `description` metadata. Use it for a quick steer on the scout's focus without loading the full skill body. Empty if the skill is not currently present on the team or carries no description. */
      readonly description: string;
      /** Where this scout came from: `canonical` for a scout PostHog ships and maintains (seeded from `products/signals/skills/`), or `custom` for one a team hand-authored on this project. Use it to badge built-in vs custom scouts instead of a hardcoded name list. Defaults to `custom` if the skill is not currently present on the team. */
      readonly scout_origin: ScoutOriginEnum;
      /** Whether this scout runs on its schedule. Disabled scouts are skipped by the coordinator. */
      enabled?: boolean;
      /** Whether the scout writes findings to the inbox. False = dry-run: it runs and logs but emits nothing. */
      emit?: boolean;
      /**
         * Minutes between runs (30–43200). The scout runs once this interval has elapsed since its last run.
         * @minimum 30
         * @maximum 43200
         */
      run_interval_minutes?: number;
      /**
         * When the coordinator last dispatched this scout. Null if it has never run.
         * @nullable
         */
      readonly last_run_at: string | null;
      readonly created_at: string;
    }

    /**
     * Request body for registering a scout config without waiting for the coordinator tick.
     *
     * Upsert keyed on `skill_name`: if the coordinator (or a concurrent caller) already
     * registered the row, the provided tunables are applied to it instead.
     */
    export interface SignalScoutConfigCreate {
      /**
         * The `signals-scout-*` skill to register a config for. The skill must already exist on this project — author it via the skills store first.
         * @maxLength 200
         */
      skill_name: string;
      /** Whether this scout runs on its schedule. Defaults to true. */
      enabled?: boolean;
      /** Whether the scout writes findings to the inbox. False = dry-run: it runs and logs but emits nothing. Defaults to true. */
      emit?: boolean;
      /**
         * Minutes between runs (30–43200). Defaults to 1440 (every 24 hours).
         * @minimum 30
         * @maximum 43200
         */
      run_interval_minutes?: number;
    }

    /**
     * One finding a scout run emitted to the inbox — the persisted, queryable record of
     * *what* the run surfaced, returned by `signals-scout-runs-emissions-list`. The emitted text
     * lives in `description`; `source_id` is the join key (`run:<run_id>:finding:<finding_id>`)
     * back into the underlying signal store.
     */
    export interface SignalScoutEmission {
      readonly id: string;
      /** UUID of the `SignalScoutRun` that emitted this finding. */
      run_id: string;
      /** Stable id the finding was emitted under; matches an entry in the run's `emitted_finding_ids`. */
      finding_id: string;
      /** The emitted finding prose — the signal's `description` as surfaced to the inbox. */
      description: string;
      /**
         * Agent's weight for the signal in [0, 1]. Drives ranking in the inbox.
         * @minimum 0
         * @maximum 1
         */
      weight: number;
      /**
         * Agent's confidence the finding is real in [0, 1].
         * @minimum 0
         * @maximum 1
         */
      confidence: number;
      /** Optional severity tag — one of P0, P1, P2, P3, P4 — or null if the run didn't set one.
       *
       * * `P0` - P0
       * * `P1` - P1
       * * `P2` - P2
       * * `P3` - P3
       * * `P4` - P4 */
      severity: AutonomyPriorityEnum | null;
      /** Slug tags the scout attached to this finding (lowercase kebab-case, e.g. `cost-spike`). Empty list when the run set none. */
      tags: string[];
      /** Deterministic `run:<run_id>:finding:<finding_id>` — the join key into the underlying signal store. */
      source_id: string;
      /** ISO-8601 timestamp the finding was emitted. */
      emitted_at: string;
    }

    /**
     * Response for an on-demand (`run now`) scout dispatch.
     *
     * The run executes asynchronously on the Temporal worker, so there is no `SignalScoutRun`
     * row yet at response time — the bridge row is created once the run's first turn starts.
     * Poll the scout's runs (`signals-scout-runs-list`) to see the resulting run and its findings.
     */
    export interface SignalScoutManualRun {
      /** The `signals-scout-*` skill that was dispatched. */
      skill_name: string;
      /** Temporal workflow id for the dispatched run. The run executes asynchronously; poll the scout's runs to see the resulting run row, its status, and any emitted findings. */
      workflow_id: string;
      /** True when a new run was dispatched. The endpoint returns 409 instead when a run for this scout is already in progress. */
      started: boolean;
    }

    /**
     * Full `SignalScoutRun` projection used by `get-run`. Same shape as the summary
     * today; kept distinct so future detail-only extensions (linked Signal rows,
     * LLMA token-cost join) can land here without bloating the list response.
     */
    export interface SignalScoutRunDetail {
      /** UUID of the bridge row. */
      run_id: string;
      /** Canonical skill name the run executed (e.g. `signals-scout-general`). */
      skill_name: string;
      /** Skill version snapshotted at run start. */
      skill_version: number;
      /** Status from the linked TaskRun: not_started | queued | in_progress | completed | failed | cancelled. */
      status: string;
      /** ISO-8601 timestamp the bridge row was created — the field `date_from` / `date_to` filter and order on. Use this (not `started_at`) as the `date_to` cursor when walking past the 100-row cap, so runs created in the gap between a boundary run's TaskRun and its bridge row aren't skipped. */
      created_at: string;
      /** ISO-8601 timestamp the TaskRun was created. */
      started_at: string;
      /**
         * ISO-8601 timestamp the TaskRun completed; null while still running.
         * @nullable
         */
      completed_at: string | null;
      /**
         * UUID of the Tasks `Task` the scout span ran inside.
         * @nullable
         */
      task_id?: string | null;
      /**
         * UUID of the Tasks `TaskRun`. Pairs with `task_id` to deep-link.
         * @nullable
         */
      task_run_id?: string | null;
      /**
         * Relative deep-link to the Tasks UI for this run, e.g. `/project/{team_id}/tasks/{task_id}?runId={task_run_id}`.
         * @nullable
         */
      task_url?: string | null;
      /** One-paragraph close-out the scout wrote at end-of-run. Empty string for runs that errored before close-out. The dedupe key for non-emitting runs. */
      summary: string;
      /**
         * Full `error_message` from the linked TaskRun, surfaced only for failed/cancelled runs (null otherwise, including on success). Use `failure_reason` for a concise scan-friendly summary.
         * @nullable
         */
      error?: string | null;
      /**
         * Concise derived reason the run didn't complete cleanly — the first line of `error` (bounded), or a status-derived fallback. Null unless the run terminated failed/cancelled. Read this to see at a glance *why* a run emitted nothing without pulling full stack traces.
         * @nullable
         */
      failure_reason?: string | null;
      /** Number of findings this run actually emitted to the inbox. 0 for runs that investigated but surfaced nothing, or ran dry-run / before AI approval. `> 0` means the run produced at least one `Signal`. */
      emitted_count: number;
      /** The `finding_id`s behind `emitted_count`, in emit order. Each maps to a `Signal` with `source_id = run:<run_id>:finding:<finding_id>`. Empty for non-emitting runs. */
      emitted_finding_ids: string[];
      /** The `SignalReport` ids this run authored directly via the `emit_report` channel, in emit order. Separate from `emitted_finding_ids` (weak `emit_signal` findings) — a report-authoring scout writes a full report here instead. Empty for runs that authored no report. */
      emitted_report_ids: string[];
      /** The `SignalReport` ids this run mutated via the `edit_report` channel (rewrote title/summary and/or appended a note), deduped. Distinct from `emitted_report_ids`: edit can target any inbox report, so these are generally not reports the run authored. Empty for runs that edited no report. */
      edited_report_ids: string[];
    }

    /**
     * Lightweight projection of a `SignalScoutRun` row used by `search-recent-runs`.
     *
     * Status and timestamps flow from the linked `tasks.TaskRun`.
     */
    export interface SignalScoutRunSummary {
      /** UUID of the bridge row. */
      run_id: string;
      /** Canonical skill name the run executed (e.g. `signals-scout-general`). */
      skill_name: string;
      /** Skill version snapshotted at run start. */
      skill_version: number;
      /** Status from the linked TaskRun: not_started | queued | in_progress | completed | failed | cancelled. */
      status: string;
      /** ISO-8601 timestamp the bridge row was created — the field `date_from` / `date_to` filter and order on. Use this (not `started_at`) as the `date_to` cursor when walking past the 100-row cap, so runs created in the gap between a boundary run's TaskRun and its bridge row aren't skipped. */
      created_at: string;
      /** ISO-8601 timestamp the TaskRun was created. */
      started_at: string;
      /**
         * ISO-8601 timestamp the TaskRun completed; null while still running.
         * @nullable
         */
      completed_at: string | null;
      /**
         * UUID of the Tasks `Task` the scout span ran inside.
         * @nullable
         */
      task_id?: string | null;
      /**
         * UUID of the Tasks `TaskRun`. Pairs with `task_id` to deep-link.
         * @nullable
         */
      task_run_id?: string | null;
      /**
         * Relative deep-link to the Tasks UI for this run, e.g. `/project/{team_id}/tasks/{task_id}?runId={task_run_id}`.
         * @nullable
         */
      task_url?: string | null;
      /** One-paragraph close-out the scout wrote at end-of-run. Empty string for runs that errored before close-out. The dedupe key for non-emitting runs. */
      summary: string;
      /**
         * Full `error_message` from the linked TaskRun, surfaced only for failed/cancelled runs (null otherwise, including on success). Use `failure_reason` for a concise scan-friendly summary.
         * @nullable
         */
      error?: string | null;
      /**
         * Concise derived reason the run didn't complete cleanly — the first line of `error` (bounded), or a status-derived fallback. Null unless the run terminated failed/cancelled. Read this to see at a glance *why* a run emitted nothing without pulling full stack traces.
         * @nullable
         */
      failure_reason?: string | null;
      /** Number of findings this run actually emitted to the inbox. 0 for runs that investigated but surfaced nothing, or ran dry-run / before AI approval. `> 0` means the run produced at least one `Signal`. */
      emitted_count: number;
      /** The `finding_id`s behind `emitted_count`, in emit order. Each maps to a `Signal` with `source_id = run:<run_id>:finding:<finding_id>`. Empty for non-emitting runs. */
      emitted_finding_ids: string[];
      /** The `SignalReport` ids this run authored directly via the `emit_report` channel, in emit order. Separate from `emitted_finding_ids` (weak `emit_signal` findings) — a report-authoring scout writes a full report here instead. Empty for runs that authored no report. */
      emitted_report_ids: string[];
      /** The `SignalReport` ids this run mutated via the `edit_report` channel (rewrote title/summary and/or appended a note), deduped. Distinct from `emitted_report_ids`: edit can target any inbox report, so these are generally not reports the run authored. Empty for runs that edited no report. */
      edited_report_ids: string[];
    }

    export interface SignalUserAutonomyConfig {
      readonly id: string;
      readonly user: _User;
      autostart_priority?: AutonomyPriorityEnum | BlankEnum | null;
      /**
         * ID of the Slack Integration to deliver inbox-item notifications through, or null when notifications are disabled.
         * @nullable
         */
      readonly slack_notification_integration_id: number | null;
      /**
         * Slack channel target in the same `channel_id|#channel-name` shape PostHog uses elsewhere (only the channel id is required). Null disables Slack notifications.
         * @maxLength 255
         * @nullable
         */
      slack_notification_channel?: string | null;
      /** Minimum report priority that triggers a Slack notification. P0 is highest. Null means notify on every priority (and reports without a priority judgment).
       *
       * * `P0` - P0
       * * `P1` - P1
       * * `P2` - P2
       * * `P3` - P3
       * * `P4` - P4 */
      slack_notification_min_priority?: AutonomyPriorityEnum | BlankEnum | null;
      readonly created_at: string;
      readonly updated_at: string;
    }

    /**
     * Full LLM-generated summary JSON. Contains `segments` (chronological journey segments), `key_actions` (per-segment events with `abandonment` / `confusion` / `exception` flags — the structured source of session-level problems), `segment_outcomes`, and `session_outcome`. Video-based runs additionally include a `sentiment` block.
     */
    export type SingleSessionSummarySummary = { [key: string]: unknown };

    /**
     * Optional context passed to the summary at generation time (e.g. `focus_area`).
     * @nullable
     */
    export type SingleSessionSummaryExtraSummaryContext = {
      readonly focus_area?: string;
    } | null;

    /**
     * `SessionSummaryRunMeta` — model used, whether video-based visual confirmation was applied, and visual-confirmation event-to-asset mappings.
     * @nullable
     */
    export type SingleSessionSummaryRunMetadata = { [key: string]: unknown } | null;

    /**
     * Full session summary, including the generated `summary` JSON content.
     */
    export interface SingleSessionSummary {
      readonly id: string;
      /** Session replay ID */
      readonly session_id: string;
      /**
         * Distinct ID of the session's user
         * @nullable
         */
      readonly distinct_id: string | null;
      /**
         * Session start time
         * @nullable
         */
      readonly session_start_time: string | null;
      /**
         * Session duration in seconds
         * @nullable
         */
      readonly session_duration: number | null;
      /** Full LLM-generated summary JSON. Contains `segments` (chronological journey segments), `key_actions` (per-segment events with `abandonment` / `confusion` / `exception` flags — the structured source of session-level problems), `segment_outcomes`, and `session_outcome`. Video-based runs additionally include a `sentiment` block. */
      readonly summary: SingleSessionSummarySummary;
      /** Event IDs (capped at 100) where exceptions occurred during the session — extracted from the summary for searchability. */
      readonly exception_event_ids: readonly string[];
      /**
         * Optional context passed to the summary at generation time (e.g. `focus_area`).
         * @nullable
         */
      readonly extra_summary_context: SingleSessionSummaryExtraSummaryContext;
      /**
         * `SessionSummaryRunMeta` — model used, whether video-based visual confirmation was applied, and visual-confirmation event-to-asset mappings.
         * @nullable
         */
      readonly run_metadata: SingleSessionSummaryRunMetadata;
      readonly created_at: string;
      readonly created_by: UserBasic | null;
    }

    export interface SlackChannel {
      /** Slack channel ID (e.g. C0123ABC) — pass to cdp-functions inputs.channel. */
      id: string;
      /** Slack channel name without the leading '#'. */
      name: string;
      /** True if the channel is private. */
      is_private: boolean;
      /** True if the PostHog Slack app is a member of the channel and can post to it. */
      is_member: boolean;
      /** True if the channel is shared with another Slack workspace. */
      is_ext_shared: boolean;
      /** True if the channel is private and the PostHog Slack app cannot access it. */
      is_private_without_access: boolean;
    }

    export interface SlackChannelsResponse {
      /** Slack channels visible to the PostHog Slack app. */
      channels: SlackChannel[];
      /**
         * ISO 8601 timestamp of the last full Slack API refresh (only set on full lists, not single-channel lookups).
         * @nullable
         */
      lastRefreshedAt?: string | null;
      /** Whether more channels match the current search beyond this page. */
      has_more?: boolean;
    }

    /**
     * The internal sandbox run the discovery agent used to pick this run's repo.
     *
     * Only present when the originating mention was ambiguous (multiple candidate
     * repos, no explicit mention) — that's the only path that spins up a research
     * sandbox. Null otherwise.
     */
    export interface SlackThreadContextRepoResearch {
      /** UUID of the internal repo-research Task. */
      task_id: string;
      /** UUID of the internal repo-research TaskRun. */
      run_id: string;
      /**
         * Research run status, or null if the run row could not be loaded.
         * @nullable
         */
      status: string | null;
      /** Temporal workflow id for the research sandbox run (`task-processing-<task_id>-<run_id>`). */
      task_processing_workflow_id: string;
      /**
         * Full Temporal Web UI URL for the research workflow; null when `TEMPORAL_UI_HOST` is unset.
         * @nullable
         */
      task_processing_workflow_url: string | null;
      /**
         * Live sandbox tunnel URL for the research run, when one was attached.
         * @nullable
         */
      sandbox_url: string | null;
      /** Absolute URL to the research task detail page (carries `?ph_debug=true`). */
      task_view_url: string;
      /**
         * Presigned S3 URL for the research run's JSONL log transcript (valid ~1 hour).
         * @nullable
         */
      log_url: string | null;
    }

    /**
     * Slack-side identifiers and the mapping metadata for a thread → task lookup.
     */
    export interface SlackThreadContextThread {
      /** Echoed input URL. */
      url: string;
      /** Slack channel id parsed from the URL (e.g. C0ACRAMJUAG). */
      channel: string;
      /** Slack thread_ts (e.g. 1779956938.619299). */
      thread_ts: string;
      /**
         * Slack workspace id (e.g. T…). Null when no mapping exists yet.
         * @nullable
         */
      slack_workspace_id: string | null;
      /**
         * The Slack user who triggered the task. Null when no mapping exists yet.
         * @nullable
         */
      mentioning_slack_user_id: string | null;
    }

    /**
     * The PostHog Task linked to the Slack thread.
     */
    export interface SlackThreadContextTask {
      /** UUID of the Task row. */
      id: string;
      /** Team that owns the task. */
      team_id: number;
      /** Task title (typically the first ~255 chars of the Slack ask). */
      title: string;
      /**
         * Resolved repository in `org/repo` form, or null if the run started without a repo.
         * @nullable
         */
      repository: string | null;
      /** `Task.OriginProduct` (`slack` for slack-originated tasks). */
      origin_product: string;
      /** When the task was created (server-side timestamp). */
      created_at: string;
      /** Absolute URL to the task detail page in the PostHog app. */
      url: string;
    }

    /**
     * One TaskRun and its associated Temporal workflow handles.
     */
    export interface SlackThreadContextRun {
      /** UUID of the TaskRun row. */
      id: string;
      /** Run status (queued/in_progress/completed/failed/…). */
      status: string;
      /** When the run was created. */
      created_at: string;
      /**
         * When the run reached a terminal state, or null while still running.
         * @nullable
         */
      completed_at: string | null;
      /**
         * Live sandbox tunnel URL, when one was attached.
         * @nullable
         */
      sandbox_url: string | null;
      /**
         * PR URL produced by the run, when one was opened.
         * @nullable
         */
      pr_url: string | null;
      /**
         * Error captured on terminal failure, or null on success.
         * @nullable
         */
      error_message: string | null;
      /** Temporal workflow id for the sandbox/agent run (`task-processing-<task_id>-<run_id>`). */
      task_processing_workflow_id: string;
      /**
         * Full Temporal Web UI URL for the task-processing workflow; null when `TEMPORAL_UI_HOST` is unset.
         * @nullable
         */
      task_processing_workflow_url: string | null;
      /**
         * Temporal workflow id of the Slack mention that dispatched this run (`posthog-code-mention-<workspace>:<event_id_or_channel:ts>`). Null for runs created before this field was persisted.
         * @nullable
         */
      mention_workflow_id: string | null;
      /**
         * Full Temporal Web UI URL for the mention dispatch workflow; null when unavailable.
         * @nullable
         */
      mention_workflow_url: string | null;
      /** Absolute URL to the task detail page focused on this run. */
      task_view_url: string;
      /**
         * Presigned S3 URL for the run's full JSONL log transcript (valid ~1 hour).
         * @nullable
         */
      log_url: string | null;
      /** The discovery-agent sandbox that picked this run's repo, when the mention was ambiguous. */
      repo_research: SlackThreadContextRepoResearch | null;
    }

    /**
     * Top-level response for the slack-thread debug endpoint.
     */
    export interface SlackThreadContextResponse {
      /** Slack-side identifiers and the mapping metadata. */
      thread: SlackThreadContextThread;
      /** Linked PostHog Task. Null when no mapping was found for the thread. */
      task: SlackThreadContextTask | null;
      /** All runs on the task, oldest first. Empty when no mapping was found. */
      runs: SlackThreadContextRun[];
    }

    export interface SourceConnectLink {
      /** The source type the link is for. */
      source_type: string;
      /** What the user will do on the connect page: 'oauth' = authorize an account in their browser; 'credentials' = enter connection details (or pick OAuth where the source offers both). Either way secrets never pass through the agent, and the result is always a stored credential id.
       *
       * * `oauth` - oauth
       * * `credentials` - credentials */
      auth_method: AuthMethodEnum;
      /** Full URL to share with the user. It opens the source's connection form in PostHog — credentials never pass through the agent or the chat. */
      connect_url: string;
      /** Next steps for the agent to relay to the user. */
      instructions: string;
    }

    export interface SourceCredential {
      /** Stored credential id. Pass to the setup endpoint as {'credential_id': <id>} to create the source. */
      credential_id: string;
      /** The source type the stored credentials are for. */
      source_type: string;
      /** When the credentials were stored. */
      created_at: string;
      /** When the stored credentials expire. Unconsumed credentials are unusable past this time. */
      expires_at: string;
    }

    /**
     * Connection details as flat keys for the source_type — the same fields the create flow accepts (host, port, password, API key, …). Checked against a live connection before being stored.
     */
