    export interface SourceMappingSuggestion {
      /** The raw utm_source value seen on events */
      raw_utm_source: string;
      /** Integration key it maps to */
      suggested_target: string;
      /** Human-readable name of the suggested integration */
      suggested_target_display_name: string;
      /** Why this mapping is suggested */
      reason: string;
    }

    /**
     * * `none` - none
     * * `auto` - auto
     * * `mapped` - mapped
     */
    export type SourceMatchEnum = typeof SourceMatchEnum[keyof typeof SourceMatchEnum];


    export const SourceMatchEnum = {
      None: 'none',
      Auto: 'auto',
      Mapped: 'mapped',
    } as const;

    export interface SourcePreviewColumn {
      /** Column name as it appears in the previewed rows. */
      name: string;
      /** JSON type inferred from the first non-null value: string, integer, number, boolean, object, array, or null. */
      type: string;
    }

    /**
     * Source config as flat keys. For source_type 'Custom': 'manifest_json' (a stringified RESTAPIConfig describing client.base_url, auth, and resources) plus the credential for the manifest's declared auth type — 'auth_token' (bearer), 'auth_api_key' (api_key), or 'auth_password' (http_basic). Secrets stay in these auth_* keys, never inline in the manifest.
     */
    export type SourcePreviewRequestPayload = { [key: string]: unknown };

