      session_recording_retention_period?: SessionRecordingRetentionPeriodEnum;
      session_replay_config?: unknown;
      survey_config?: unknown;
      week_start_day?: WeekStartDayEnum | null;
      /** @nullable */
      primary_dashboard?: number | null;
      /** @nullable */
