      /** Whether this project serves B2B or B2C customers, used to optimize the UI layout.
       *
       * * `b2b` - B2B
       * * `b2c` - B2C
       * * `other` - Other */
      business_model?: BusinessModelEnum | BlankEnum | null;
      /** @nullable */
